import { CommonModule } from "@angular/common";
import { Component, OnInit, inject } from "@angular/core";
import { ActivatedRoute, Router, RouterLink } from "@angular/router";
import { DomSanitizer, SafeResourceUrl } from "@angular/platform-browser";
import { StudentService } from "../../services/student.service";

@Component({
  selector: "app-student-course",
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: "./student-course.component.html",
  styleUrl: "./student-course.component.css"
})
export class StudentCourseComponent implements OnInit {
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);
  private readonly studentService = inject(StudentService);
  private readonly sanitizer = inject(DomSanitizer);

  courseData: any = null;
  loading = true;
  errorMessage = "";
  selectedVideo: any = null;
  selectedVideoId: number | null = null;
  selectedVideoEmbedUrl: SafeResourceUrl | null = null;
  resourceSectionOpen = true;
  quizSectionOpen = true;

  ngOnInit(): void {
    this.route.params.subscribe((params) => {
      const courseId = Number(params["id"]);
      if (!courseId) {
        this.router.navigateByUrl("/student/dashboard");
        return;
      }
      this.loadCourse(courseId, this.selectedVideoId ?? undefined);
    });
  }

  loadCourse(courseId: number, preferredVideoId?: number): void {
    this.loading = true;
    this.studentService.course(courseId).subscribe({
      next: (data) => {
        this.courseData = data;
        this.applySelectedVideo(preferredVideoId);
        this.loading = false;
      },
      error: (error) => {
        this.errorMessage = error?.error?.message ?? "Failed to load course";
        this.loading = false;
      }
    });
  }

  completeVideo(videoId: number): void {
    this.studentService.completeVideo(videoId).subscribe({
      next: () => this.loadCourse(this.courseData.course.id, videoId)
    });
  }

  startQuiz(quizId: number, locked: boolean): void {
    if (locked) {
      return;
    }
    this.router.navigate(["/student/quiz", quizId], {
      queryParams: { courseId: this.courseData?.course?.id }
    });
  }

  chooseVideo(video: any): void {
    this.selectedVideo = video;
    this.selectedVideoId = video.videoId;
    this.selectedVideoEmbedUrl = this.toEmbedUrl(video.videoUrl);
  }

  openVideo(videoUrl: string): void {
    window.open(videoUrl, "_blank", "noopener");
  }

  toggleResourceSection(): void {
    this.resourceSectionOpen = !this.resourceSectionOpen;
  }

  toggleQuizSection(): void {
    this.quizSectionOpen = !this.quizSectionOpen;
  }

  thumbnailFor(videoUrl: string): string {
    const youtubeId = this.extractYoutubeId(videoUrl);
    if (youtubeId) {
      return `https://img.youtube.com/vi/${youtubeId}/hqdefault.jpg`;
    }
    return "https://images.unsplash.com/photo-1517430816045-df4b7de11d1d?auto=format&fit=crop&w=1200&q=80";
  }

  private applySelectedVideo(preferredVideoId?: number): void {
    const videos = this.courseData?.videos ?? [];
    if (videos.length === 0) {
      this.selectedVideo = null;
      this.selectedVideoId = null;
      this.selectedVideoEmbedUrl = null;
      return;
    }

    const picked =
      videos.find((video: any) => video.videoId === preferredVideoId) ??
      videos.find((video: any) => !video.completed) ??
      videos[0];

    this.chooseVideo(picked);
  }

  private toEmbedUrl(videoUrl: string): SafeResourceUrl | null {
    const youtubeId = this.extractYoutubeId(videoUrl);
    if (youtubeId) {
      return this.sanitizer.bypassSecurityTrustResourceUrl(`https://www.youtube.com/embed/${youtubeId}?rel=0`);
    }

    if (videoUrl.endsWith(".mp4")) {
      return this.sanitizer.bypassSecurityTrustResourceUrl(videoUrl);
    }

    return null;
  }

  private extractYoutubeId(urlValue: string): string | null {
    try {
      const url = new URL(urlValue);
      const host = url.hostname.toLowerCase();
      if (host.includes("youtu.be")) {
        return url.pathname.replace("/", "") || null;
      }
      if (host.includes("youtube.com")) {
        if (url.searchParams.get("v")) {
          return url.searchParams.get("v");
        }
        const parts = url.pathname.split("/").filter(Boolean);
        if (parts.length >= 2 && parts[0] === "embed") {
          return parts[1];
        }
      }
      return null;
    } catch {
      return null;
    }
  }
}
<div class="container">
  @if (loading) {
    <p>Loading course...</p>
  } @else if (errorMessage) {
    <p class="error">{{ errorMessage }}</p>
  } @else if (courseData) {
    <section class="panel hero">
      <h1>{{ courseData.course.title }}</h1>
      <p>{{ courseData.course.description }}</p>
      <p class="muted">
        Mandatory video completed: {{ courseData.progress.mandatoryCompleted }}/{{ courseData.progress.mandatoryTotal }}
        ({{ courseData.progress.percent }}%)
      </p>
    </section>

    <section class="panel block activity-block">
      <h2>Activity/Resources</h2>

      @if (selectedVideo) {
        <div class="featured-video">
          @if (selectedVideoEmbedUrl) {
            <iframe
              [src]="selectedVideoEmbedUrl"
              title="Course Video Player"
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
              allowfullscreen>
            </iframe>
          } @else {
            <button class="video-fallback" type="button" (click)="openVideo(selectedVideo.videoUrl)">
              <img [src]="thumbnailFor(selectedVideo.videoUrl)" [alt]="selectedVideo.title">
              <span>Play {{ selectedVideo.title }}</span>
            </button>
          }

          <div class="featured-meta">
            <h3>{{ selectedVideo.title }}</h3>
            <p>{{ selectedVideo.description }}</p>
            <div class="video-action-row">
              <span>{{ selectedVideo.durationMinutes }} min</span>
              @if (selectedVideo.completed) {
                <span class="badge">Completed</span>
              } @else {
                <span class="badge warn">Pending</span>
              }
              <button class="btn btn-outline" type="button" (click)="openVideo(selectedVideo.videoUrl)">
                Open Video
              </button>
              <button
                class="btn"
                type="button"
                [disabled]="selectedVideo.completed"
                (click)="completeVideo(selectedVideo.videoId)">
                {{ selectedVideo.completed ? "Completed" : "Mark Complete" }}
              </button>
            </div>
          </div>
        </div>
      }

      <div class="video-list">
        @for (video of courseData.videos; track video.videoId) {
          <button
            class="video-item"
            type="button"
            [class.active]="video.videoId === selectedVideoId"
            (click)="chooseVideo(video)">
            <span class="order">#{{ video.sortOrder }}</span>
            <span class="title">{{ video.title }}</span>
            <span class="time">{{ video.durationMinutes }} min</span>
            @if (video.completed) {
              <span class="badge">Done</span>
            } @else {
              <span class="badge warn">Pending</span>
            }
          </button>
        }
      </div>
    </section>

    <section class="panel block">
      <button class="section-toggle" type="button" (click)="toggleResourceSection()">
        <span>Resources / Material</span>
        <span class="toggle-icon">{{ resourceSectionOpen ? "▾" : "▸" }}</span>
      </button>
      @if (resourceSectionOpen) {
        @if (courseData.materials.length === 0) {
          <p class="muted">Tiada resource lagi.</p>
        } @else {
          <ul class="resource-list">
            @for (material of courseData.materials; track material.materialId) {
              <li>
                <strong>{{ material.title }}</strong>
                <span class="badge">{{ material.materialType }}</span>
                <a [href]="material.resourceUrl" target="_blank" rel="noopener">Open</a>
              </li>
            }
          </ul>
        }
      }
    </section>

    <section class="panel block">
      <button class="section-toggle" type="button" (click)="toggleQuizSection()">
        <span>Quiz</span>
        <span class="toggle-icon">{{ quizSectionOpen ? "▾" : "▸" }}</span>
      </button>
      @if (quizSectionOpen) {
        @if (courseData.quizzes.length === 0) {
          <p class="muted">Belum ada quiz dipublish.</p>
        } @else {
          <div class="quiz-list">
            @for (quiz of courseData.quizzes; track quiz.quizId) {
              <div class="quiz-item">
                <div>
                  <h3>{{ quiz.title }}</h3>
                  <p class="muted">Due date: {{ quiz.closeAt ? (quiz.closeAt | date: "medium") : "Not set" }}</p>
                  <p class="muted">{{ quiz.timeLimitMinutes }} min | Pass mark {{ quiz.passingMark }}%</p>
                </div>
                <div class="quiz-actions">
                  @if (quiz.locked) {
                    <span class="badge warn">Locked</span>
                  } @else {
                    <span class="badge">Ready</span>
                  }
                  <button class="btn" [disabled]="quiz.locked" (click)="startQuiz(quiz.quizId, quiz.locked)">
                    Attempt Quiz
                  </button>
                </div>
              </div>
            }
          </div>
        }
      }
    </section>
  }
</div>
